function normalizeOrderId(value: string): string {
  return value.trim().toUpperCase();
}

function isValidOrderId(value: string): boolean {
  return /^ARC-\d{4}-[0-9A-F]{8}$/.test(value);
}

function isOrderStatus(value: unknown): value is OrderStatus {
  return value === 'pending_payment'
    || value === 'processing'
    || value === 'in-transit'
    || value === 'delivered'
    || value === 'cancelled';
}

function readResponseString(value: unknown): string {
  return typeof value === 'string' ? value.trim() : '';
}

interface OrderStatusFormProps {
  copy: OrderStatusCopy;
  loading: boolean;
  orderId: string;
  onOrderIdChange: (value: string) => void;
  onSubmit: () => void;
}

function OrderStatusForm({
  copy,
  loading,
  orderId,
  onOrderIdChange,
  onSubmit,
}: OrderStatusFormProps): JSX.Element {
  return (
    <form
      className='mt-10 grid gap-4'
      onSubmit={(event) => {
        event.preventDefault();
        onSubmit();
      }}
    >
      <label className='type-label' style={{ color: 'var(--fg)' }} htmlFor='order-status-id'>
        {copy.inputLabel}
      </label>
      <div className='flex flex-col sm:flex-row gap-3'>
        <input
          id='order-status-id'
          value={orderId}
          onChange={(event) => onOrderIdChange(event.target.value)}
          placeholder={copy.inputPlaceholder}
          style={{
            flex: 1,
